/**
 * 🎵 Audio Utilities
 * 
 * Funções utilitárias para processamento de áudio:
 * - Extração de waveform data via Web Audio API
 * - Formatação de duração
 * - Validação de formatos
 * - Helpers para audio management
 * 
 * @module audio-utils
 */

// ============================================================================
// TYPES
// ============================================================================

/** Formatos de áudio suportados */
export type AudioFormat = 'mp3' | 'wav' | 'ogg' | 'webm' | 'aac' | 'm4a';

/** MIME types de áudio suportados */
export const AUDIO_MIME_TYPES: Record<AudioFormat, string> = {
  mp3: 'audio/mpeg',
  wav: 'audio/wav',
  ogg: 'audio/ogg',
  webm: 'audio/webm',
  aac: 'audio/aac',
  m4a: 'audio/mp4',
};

/** Dados de waveform pré-computados */
export interface WaveformData {
  peaks: number[];
  duration: number;
  sampleRate: number;
  channels: number;
}

/** Item de áudio do projeto */
export interface AudioItem {
  id: string;
  name: string;
  url: string;
  format: AudioFormat | string;
  duration: number;
  size: number;
  waveform?: number[];
  uploadedAt: Date;
  assignedTo?: {
    type: 'narration' | 'background';
    sceneId?: string;
  };
}

/** Uso do áudio no projeto */
export type AudioUsage = 'narration' | 'background' | 'effect';

// ============================================================================
// CONSTANTS
// ============================================================================

/** Tamanho máximo de upload (100MB) */
export const MAX_AUDIO_SIZE = 100 * 1024 * 1024;

/** Extensões de áudio permitidas */
export const ALLOWED_AUDIO_EXTENSIONS: AudioFormat[] = ['mp3', 'wav', 'ogg', 'webm', 'aac', 'm4a'];

/** Número de amostras para waveform (barras visíveis) */
export const WAVEFORM_SAMPLES = 100;

// ============================================================================
// FORMAT HELPERS
// ============================================================================

/**
 * Formata duração em segundos para string "MM:SS"
 */
export function formatAudioDuration(seconds: number): string {
  if (!Number.isFinite(seconds) || seconds < 0) return '0:00';
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
}

/**
 * Formata tamanho em bytes para string legível
 */
export function formatAudioSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

/**
 * Extrai extensão/formato de um filename
 */
export function getAudioFormat(filename: string): AudioFormat | null {
  const ext = filename.split('.').pop()?.toLowerCase();
  if (ext && ALLOWED_AUDIO_EXTENSIONS.includes(ext as AudioFormat)) {
    return ext as AudioFormat;
  }
  return null;
}

/**
 * Verifica se um MIME type é um formato de áudio suportado
 */
export function isValidAudioMimeType(mimeType: string): boolean {
  return Object.values(AUDIO_MIME_TYPES).includes(mimeType);
}

/**
 * Verifica se um arquivo é áudio válido
 */
export function validateAudioFile(file: { name: string; size: number; type: string }): {
  valid: boolean;
  error?: string;
} {
  if (file.size > MAX_AUDIO_SIZE) {
    return {
      valid: false,
      error: `Arquivo muito grande. Máximo ${MAX_AUDIO_SIZE / (1024 * 1024)}MB.`,
    };
  }

  if (!isValidAudioMimeType(file.type)) {
    const format = getAudioFormat(file.name);
    if (!format) {
      return {
        valid: false,
        error: `Formato não suportado. Use: ${ALLOWED_AUDIO_EXTENSIONS.join(', ')}.`,
      };
    }
  }

  return { valid: true };
}

// ============================================================================
// WAVEFORM EXTRACTION
// ============================================================================

/**
 * Gera waveform data a partir de um ArrayBuffer de áudio.
 * Usa Web Audio API quando disponível, senão retorna waveform determinístico.
 */
export async function extractWaveform(
  audioBuffer: ArrayBuffer,
  numSamples: number = WAVEFORM_SAMPLES,
): Promise<WaveformData> {
  // Server-side or no AudioContext: return deterministic waveform
  if (typeof window === 'undefined' || !window.AudioContext) {
    return {
      peaks: generateDeterministicWaveform(audioBuffer.byteLength, numSamples),
      duration: 0,
      sampleRate: 44100,
      channels: 1,
    };
  }

  try {
    const audioContext = new AudioContext();
    const decoded = await audioContext.decodeAudioData(audioBuffer.slice(0));
    const channelData = decoded.getChannelData(0);
    const peaks = computePeaks(channelData, numSamples);

    await audioContext.close();

    return {
      peaks,
      duration: decoded.duration,
      sampleRate: decoded.sampleRate,
      channels: decoded.numberOfChannels,
    };
  } catch {
    return {
      peaks: generateDeterministicWaveform(audioBuffer.byteLength, numSamples),
      duration: 0,
      sampleRate: 44100,
      channels: 1,
    };
  }
}

/**
 * Computa picos de amplitude a partir de channelData.
 * Cada amostra no resultado representa o valor máximo em um segmento.
 */
export function computePeaks(channelData: Float32Array, numSamples: number): number[] {
  const blockSize = Math.floor(channelData.length / numSamples);
  const peaks: number[] = [];

  for (let i = 0; i < numSamples; i++) {
    const start = i * blockSize;
    const end = Math.min(start + blockSize, channelData.length);
    let max = 0;

    for (let j = start; j < end; j++) {
      const abs = Math.abs(channelData[j]);
      if (abs > max) max = abs;
    }

    peaks.push(max);
  }

  // Normalize to 0-1
  const maxPeak = Math.max(...peaks, 0.001);
  return peaks.map(p => p / maxPeak);
}

/**
 * Gera waveform determinístico baseado no tamanho do arquivo.
 * Útil quando não há AudioContext disponível (SSR).
 */
export function generateDeterministicWaveform(seed: number, numSamples: number): number[] {
  const peaks: number[] = [];
  let value = (seed % 1000) / 1000;

  for (let i = 0; i < numSamples; i++) {
    // Simple hash-based pattern
    value = ((value * 9301 + 49297) % 233280) / 233280;
    const envelope = Math.sin((i / numSamples) * Math.PI);
    peaks.push(Math.min(1, Math.max(0.05, value * 0.6 + 0.4 * envelope)));
  }

  return peaks;
}

// ============================================================================
// TIME/POSITION HELPERS
// ============================================================================

/**
 * Converte posição percentual (0-1) na waveform para tempo em segundos
 */
export function waveformPositionToTime(position: number, duration: number): number {
  return Math.max(0, Math.min(duration, position * duration));
}

/**
 * Converte tempo em segundos para posição percentual (0-1) na waveform
 */
export function timeToWaveformPosition(time: number, duration: number): number {
  if (duration <= 0) return 0;
  return Math.max(0, Math.min(1, time / duration));
}
